import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it.todo("should return base premium plus processing fee for a single sword (new customer, first insurance)");
    it.todo("should return base premium plus processing fee for a single amulet");
    it.todo("should return base premium plus processing fee for a single staff");
    it.todo("should return base premium plus processing fee for a single potion");
    it.todo("should apply 50% surcharge for a cursed item");
    it.todo("should apply 30% surcharge for a highly enchanted item (enchantment >= 5)");
    it.todo("should apply 20% loyalty discount for long-standing customers (>= 2 years)");
    it.todo("should apply 10% initial assessment surcharge for first insurance");
    it.todo("should apply 15% discount on contracts after the first");
    it.todo("should price a single component at 25 G with processing fee");
    it.todo("should price a group of 3 identical components at 60 G base premium");
    it.todo("should round premium up to whole G in MHPCO's favor");
  });

  describe("claim", () => {
    it.todo("should apply 100 G deductible per damage event");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse high-enchantment items (enchantment >= 8) at 50%");
    it.todo("should fully reimburse dragon material items");
    it.todo("should track remaining cap across multiple claims on the same policy");
  });
});

